import 'dotenv/config';
import { describe, it } from 'vitest';
import type { RunOptions } from '../src/sdk';
import { AppClaw } from '../src/sdk';
describe('Recorded flow', () => {
  it('launches vodqa and swipe the first slider to the right', async () => {
    const app = new AppClaw({
      apiKey: process.env.LLM_API_KEY,
      platform: 'android',
      video: true,
      mcpDebug: true,
      silent: true,
      waitTimeout: 10000,
      waitInterval: 1000,
      locatorCache: true,
      capabilitiesFile: './tests/caps.json',
    });

    await app.run('open vodqa app');
    await app.run('click on login button');
    await app.run('click on Vertical swiping');
    await app.run('scroll down 2 times until Karma is visible', {
      scrollMode: 'short',
    } as RunOptions);
    await app.verify('if the text Karmaaa is visible');
    await app.teardown();
  }, 120000);
});
